import * as React from 'react';
import { NavigationMenu } from '@base-ui-components/react/navigation-menu';
import { screen, render, waitFor } from '@testing-library/react';
import { userEvent } from '@testing-library/user-event';

describe('NavigationMenu Bug Fixes', () => {
  describe('Issue 1: --popup-height not updated on content change', () => {
    it('should update --popup-height when content changes dynamically', async () => {
      const user = userEvent.setup();

      function TestComponent() {
        const [showExtra, setShowExtra] = React.useState(false);

        return (
          <NavigationMenu.Root>
            <NavigationMenu.Item value="test">
              <NavigationMenu.Trigger>Menu</NavigationMenu.Trigger>
              <NavigationMenu.Content>
                <div data-testid="content">
                  <p>Initial content</p>
                  {showExtra && <p data-testid="extra">Extra content that changes height</p>}
                  <button onClick={() => setShowExtra(true)}>Add Content</button>
                </div>
              </NavigationMenu.Content>
            </NavigationMenu.Item>
            <NavigationMenu.Portal>
              <NavigationMenu.Positioner>
                <NavigationMenu.Popup data-testid="popup">
                  <NavigationMenu.Viewport />
                </NavigationMenu.Popup>
              </NavigationMenu.Positioner>
            </NavigationMenu.Portal>
          </NavigationMenu.Root>
        );
      }

      render(<TestComponent />);

      const trigger = screen.getByText('Menu');
      await user.click(trigger);

      const popup = screen.getByTestId('popup');
      const initialHeight = popup.style.getPropertyValue('--popup-height');

      // Click button to add content
      const button = screen.getByText('Add Content');
      await user.click(button);

      // Wait for content to be added
      await waitFor(() => {
        expect(screen.getByTestId('extra')).toBeInTheDocument();
      });

      // The height should have been updated
      await waitFor(() => {
        const newHeight = popup.style.getPropertyValue('--popup-height');
        expect(newHeight).not.toBe(initialHeight);
        expect(newHeight).not.toBe('auto');
      });
    });
  });

  describe('Issue 2: No transition on nested NavigationMenu', () => {
    it('should apply transition when nested menu has defaultValue', async () => {
      function TestComponent() {
        return (
          <NavigationMenu.Root>
            <NavigationMenu.Item value="parent">
              <NavigationMenu.Trigger>Parent Menu</NavigationMenu.Trigger>
              <NavigationMenu.Content>
                <NavigationMenu.Root defaultValue="nested">
                  <NavigationMenu.Item value="nested">
                    <NavigationMenu.Trigger>Nested Menu</NavigationMenu.Trigger>
                    <NavigationMenu.Content data-testid="nested-content">
                      <p>Nested content</p>
                    </NavigationMenu.Content>
                  </NavigationMenu.Item>
                  <NavigationMenu.Viewport />
                </NavigationMenu.Root>
              </NavigationMenu.Content>
            </NavigationMenu.Item>
            <NavigationMenu.Portal>
              <NavigationMenu.Positioner>
                <NavigationMenu.Popup>
                  <NavigationMenu.Viewport />
                </NavigationMenu.Popup>
              </NavigationMenu.Positioner>
            </NavigationMenu.Portal>
          </NavigationMenu.Root>
        );
      }

      render(<TestComponent />);

      const trigger = screen.getByText('Parent Menu');
      const user = userEvent.setup();
      await user.click(trigger);

      // The nested content should appear with transition status
      await waitFor(() => {
        const nestedContent = screen.getByTestId('nested-content');
        expect(nestedContent).toBeInTheDocument();
        // Check for transition status data attributes
        const hasTransitionStatus = nestedContent.hasAttribute('data-transition-status') ||
                                   nestedContent.hasAttribute('data-starting') ||
                                   nestedContent.hasAttribute('data-open');
        expect(hasTransitionStatus).toBe(true);
      });
    });
  });

  describe('Issue 3: No direction-based transitions without Positioner/Popover', () => {
    it('should apply activation direction even without Positioner', async () => {
      const user = userEvent.setup();

      function TestComponent() {
        return (
          <NavigationMenu.Root orientation="horizontal">
            <NavigationMenu.Item value="item1">
              <NavigationMenu.Trigger data-testid="trigger1">Item 1</NavigationMenu.Trigger>
              <NavigationMenu.Content data-testid="content1">
                <p>Content 1</p>
              </NavigationMenu.Content>
            </NavigationMenu.Item>
            <NavigationMenu.Item value="item2">
              <NavigationMenu.Trigger data-testid="trigger2">Item 2</NavigationMenu.Trigger>
              <NavigationMenu.Content data-testid="content2">
                <p>Content 2</p>
              </NavigationMenu.Content>
            </NavigationMenu.Item>
            {/* Using viewport without Portal/Positioner */}
            <NavigationMenu.Viewport />
          </NavigationMenu.Root>
        );
      }

      render(<TestComponent />);

      // Open first item
      const trigger1 = screen.getByTestId('trigger1');
      await user.hover(trigger1);

      await waitFor(() => {
        const content1 = screen.getByTestId('content1');
        expect(content1).toBeInTheDocument();
      });

      // Move to second item (should trigger direction)
      const trigger2 = screen.getByTestId('trigger2');
      await user.hover(trigger2);

      await waitFor(() => {
        const content2 = screen.getByTestId('content2');
        expect(content2).toBeInTheDocument();
        // Should have activation direction attribute
        expect(
          content2.hasAttribute('data-activation-direction') &&
          (content2.getAttribute('data-activation-direction') === 'left' ||
           content2.getAttribute('data-activation-direction') === 'right')
        ).toBe(true);
      });
    });
  });
});

