// Add ResizeObserver to update --popup-height when content changes
const {
  currentContentRef,
} = useNavigationMenuRootContext();

React.useEffect(() => {
  if (!isActiveItem || !open || !currentContentRef.current || typeof ResizeObserver === 'undefined') {
    return undefined;
  }

  const observer = new ResizeObserver(() => {
    if (popupElement && positionerElement) {
      // Remove auto to get the actual size
      const prevPopupWidth = popupElement.style.getPropertyValue(NavigationMenuPopupCssVars.popupWidth);
      const prevPopupHeight = popupElement.style.getPropertyValue(NavigationMenuPopupCssVars.popupHeight);

      if (prevPopupWidth !== 'auto' && prevPopupHeight !== 'auto') {
        popupElement.style.setProperty(NavigationMenuPopupCssVars.popupWidth, 'auto');
        popupElement.style.setProperty(NavigationMenuPopupCssVars.popupHeight, 'auto');
      }

      const currentWidth = popupElement.offsetWidth;
      const currentHeight = popupElement.offsetHeight;

      popupElement.style.setProperty(NavigationMenuPopupCssVars.popupWidth, `${currentWidth}px`);
