        `${currentWidth}px`,
      );
      positionerElement.style.setProperty(
        NavigationMenuPositionerCssVars.positionerHeight,
        `${currentHeight}px`,
      );
    }
  });

  observer.observe(currentContentRef.current);

  return () => {
