'use client';
import * as React from 'react';
import * as ReactDOM from 'react-dom';
import { useIsoLayoutEffect } from '@base-ui-components/utils/useIsoLayoutEffect';
import { AnimationFrame } from '@base-ui-components/utils/useAnimationFrame';

export type TransitionStatus = 'starting' | 'ending' | 'idle' | undefined;

/**
 * Provides a status string for CSS animations.
 * @param open - a boolean that determines if the element is open.
 * @param enableIdleState - a boolean that enables the `'idle'` state between `'starting'` and `'ending'`
 */
export function useTransitionStatus(
  open: boolean,
  enableIdleState: boolean = false,
  deferEndingState: boolean = false,
) {
  const [transitionStatus, setTransitionStatus] = React.useState<TransitionStatus>(
    open && enableIdleState ? 'idle' : undefined,
  );
  const [mounted, setMounted] = React.useState(open);

  if (open && !mounted) {
    setMounted(true);
    setTransitionStatus('starting');
  }

  if (!open && mounted && transitionStatus !== 'ending' && !deferEndingState) {
    setTransitionStatus('ending');
  }

  if (!open && !mounted && transitionStatus === 'ending') {
    setTransitionStatus(undefined);
  }

  useIsoLayoutEffect(() => {
    if (!open && mounted && transitionStatus !== 'ending' && deferEndingState) {
      const frame = AnimationFrame.request(() => {
        setTransitionStatus('ending');
      });

      return () => {
        AnimationFrame.cancel(frame);
      };
    }

    return undefined;
  }, [open, mounted, transitionStatus, deferEndingState]);

  useIsoLayoutEffect(() => {
    if (!open || enableIdleState) {
      return undefined;
    }

    const frame = AnimationFrame.request(() => {
      ReactDOM.flushSync(() => {
        setTransitionStatus(undefined);
      });
    });

    return () => {
      AnimationFrame.cancel(frame);
    };
  }, [enableIdleState, open]);

  useIsoLayoutEffect(() => {
    if (!open || !enableIdleState) {
      return undefined;
    }

    if (open && mounted && transitionStatus !== 'idle') {
      setTransitionStatus('starting');
    }

    const frame = AnimationFrame.request(() => {
      setTransitionStatus('idle');
    });

    return () => {
      AnimationFrame.cancel(frame);
    };
  }, [enableIdleState, open, mounted, setTransitionStatus, transitionStatus]);

  return React.useMemo(
    () => ({
      mounted,
      setMounted,
      transitionStatus,
    }),
    [mounted, transitionStatus],
  );
}

content.text:
I see. Looking at lines 22-27, when `open` is initially `true`, `mounted` is set to `true` and `transitionStatus` is set to `'starting'`. But the issue might be that for nested menus, the parent might not be mounted yet when the nested menu tries to transition.

Actually, re-reading the bug report more carefully:

> When nesting another `NavigationMenu` inside a parent item (e.g. for multi-level navigation), and using a `defaultValue` to preselect a nested item, the transition effect is skipped entirely. It seems like the inner `NavigationMenu.Viewport` is delayed in rendering or measuring, and that causes the quick jump instead of a smooth transition.

The issue is that the **inner** `NavigationMenu.Viewport` is delayed. This makes sense because:
1. The parent menu needs to open first
2. Then the parent's content (which contains the nested menu) is rendered
3. Then the nested menu's viewport is created
4. But by then, the nested menu's content might already be trying to render

Looking at NavigationMenuContent.tsx line 112-116:

```typescript
const shouldRender = viewportElement !== null && mounted;

if (!viewportElement || !shouldRender) {
  return null;
}
```

So content won't render until the viewport exists. For nested menus, when defaultValue is set, the nested content tries to render immediately but the viewport doesn't exist yet. Then when the viewport does exist, it renders without transitions.

The fix could be to ensure that when a content's viewport element becomes available, it should trigger a transition. Let me think about this...

Actually, looking more carefully at NavigationMenuContent.tsx lines 62-72:

```typescript
const { mounted, setMounted, transitionStatus } = useTransitionStatus(open);

useOpenChangeComplete({
  ref,
  open,
  onComplete() {
    if (!open) {
      setMounted(false);
    }
  },
});
```

Each content has its own transition status. The issue is that when `viewportElement` becomes available, the component re-renders but `open` was already true, so no transition happens.

The fix should be to re-trigger the transition when viewportElement becomes available. Let me implement that:

